// COMPLETE, COMPILABLE C code
#include <stdio.h>
#define MOD 1163962801
int dp[1000001][22][21];
int main() {
    int n, m, t;
    scanf("%d %d %d", &n, &m, &t);
    // Initialize dp array
    for (int i = 0; i <= t; i++) {
        for (int j = 0; j < n; j++) {
            for (int k = 0; k < n - 1; k++) {
                dp[i][j][k] = 0;
            }
        }
    }
    // Initialize base case
    for (int i = 0; i < n; i++) {
        dp[0][i][0] = 1;
    }
    // Iterate over each road
    for (int i = 1; i <= t; i++) {
        for (int j = 0; j < m; j++) {
            int s, e, f, r;
            scanf("%d %d %d %d", &s, &e, &f, &r);
            // Update dp array
            for (int k = 0; k < n; k++) {
                for (int l = 0; l < n - 1; l++) {
                    dp[i][e - 1][(l + r) % (n - 1)] = (dp[i][e - 1][(l + r) % (n - 1)] + dp[i - 1][k][(l + f) % n]) % MOD;
                }
            }
        }
    }
    // Output result
    for (int i = 0; i < n; i++) {
        for (int j = 0; j < n; j++) {
            for (int k = 0; k < n - 1; k++) {
                printf("%d ", dp[t][i][j]);
            }
            printf("\n");
        }
        printf("\n");
    }
    return 0;
}

